/**
 * Screening request (ATS-ready).
 * Prerequisites:
 *  - 04 indexed JD → jobs_knowledge (prefer metadata job_id=job_001)
 *  - 08 indexed CVs → candidates_knowledge (candidate_id=cand_00x)
 *
 * No PDF re-processing here — only RAG retrieve + LLM scoring.
 */
return [{
  json: {
    job_id: 'job_001',
    job_title: 'Senior Backend Java Engineer',
    job_summary: 'Senior Backend Java Engineer requiring Java 17+, Spring Boot, Microservices, AWS, Kafka, SQL, CI/CD; preferred leadership/mentoring; 6+ years backend.',
    candidates: [
      { candidate_id: 'cand_001', candidate_name: 'Alex Rivera' },
      { candidate_id: 'cand_002', candidate_name: 'Jordan Lee' },
      { candidate_id: 'cand_003', candidate_name: 'Sam Okonkwo' }
    ]
  }
}];

const ctx = $('Build Candidate Screening Prompt').item.json;
const item = $input.first().json;
const raw = item.output ?? item.text ?? item.response ?? JSON.stringify(item);
const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
const start = text.indexOf('{');
const end = text.lastIndexOf('}');
if (start === -1 || end === -1) {
  throw new Error('Screening Agent did not return JSON. Raw: ' + text.slice(0, 500));
}
const parsed = JSON.parse(text.slice(start, end + 1));
const clamp = (n) => Math.max(0, Math.min(100, Number(n) || 0));

const criteria = parsed.criteria_scores || {};
const technical = criteria.technical || {};
const experience = criteria.experience || {};
const leadership = criteria.leadership || {};

const overall = clamp(
  parsed.overall_score ?? (
    clamp(technical.score) * 0.45 +
    clamp(experience.score) * 0.35 +
    clamp(leadership.score) * 0.20
  )
);

const rec = parsed.recommendation || {};
const decision = ['ADVANCE', 'HOLD', 'REJECT'].includes(rec.decision)
  ? rec.decision
  : (overall >= 80 ? 'ADVANCE' : overall >= 60 ? 'HOLD' : 'REJECT');

const priority = ['HIGH', 'MEDIUM', 'LOW'].includes(parsed.interview_priority)
  ? parsed.interview_priority
  : (overall >= 80 ? 'HIGH' : overall >= 60 ? 'MEDIUM' : 'LOW');

return [{
  json: {
    candidate_id: parsed.candidate_id || ctx.candidate_id,
    candidate_name: parsed.candidate_name || ctx.candidate_name,
    job_id: parsed.job_id || ctx.job_id,
    overall_score: overall,
    criteria_scores: {
      technical: {
        score: clamp(technical.score),
        weight: Number(technical.weight) || 0.45,
        rationale: technical.rationale || ''
      },
      experience: {
        score: clamp(experience.score),
        weight: Number(experience.weight) || 0.35,
        rationale: experience.rationale || ''
      },
      leadership: {
        score: clamp(leadership.score),
        weight: Number(leadership.weight) || 0.20,
        rationale: leadership.rationale || ''
      }
    },
    strengths: Array.isArray(parsed.strengths) ? parsed.strengths : [],
    gaps: Array.isArray(parsed.gaps) ? parsed.gaps : [],
    evidence: {
      matched_requirements: Array.isArray(parsed.evidence?.matched_requirements)
        ? parsed.evidence.matched_requirements : [],
      quotes_or_facts: Array.isArray(parsed.evidence?.quotes_or_facts)
        ? parsed.evidence.quotes_or_facts : [],
      missing: Array.isArray(parsed.evidence?.missing)
        ? parsed.evidence.missing : []
    },
    recommendation: {
      decision,
      summary: rec.summary || ''
    },
    interview_priority: priority
  }
}];

const req = $('Load Screening Request').first().json;
const payload = $input.first().json;
const rows = Array.isArray(payload.data) ? payload.data : $input.all().map((i) => i.json);

const ranking = [...rows]
  .sort((a, b) => (b.overall_score || 0) - (a.overall_score || 0))
  .map((c, idx) => ({ rank: idx + 1, ...c }));

return [{
  json: {
    product: 'AI Talent Copilot',
    workflow: '07 - Recruiter Screening Engine',
    architecture: 'index-once / retrieve-many',
    job_id: req.job_id,
    job_title: req.job_title,
    candidates_evaluated: ranking.length,
    collections: {
      candidates: 'candidates_knowledge',
      jobs: 'jobs_knowledge'
    },
    ranking
  }
}];
